.bt-input-single-options__wrapper {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
}

.bt-input-single-options__label-row {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
}

.bt-input-single-options__label {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  letter-spacing: 0;
}

.bt-input-single-options--error .bt-input-single-options__label {
  color: var(--text-error);
}

.bt-input-single-options--disabled .bt-input-single-options__label {
  color: var(--text-primary);
}

.bt-input-single-options__required {
  color: var(--text-error);
}

.bt-input-single-options__group {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-sm);
  align-items: center;
}

.bt-input-single-options__helper {
  display: flex;
  gap: var(--space-xs);
  align-items: center;
}

.bt-input-single-options__helper-text {
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  letter-spacing: 0;
}

.bt-input-single-options__helper-text--error {
  color: var(--text-error);
}

/**
 * BTInputSingleOptions — labeled radio button group (Figma node 702-3422).
 *
 * A flex-wrap row of BTRadioButton items with a title label above and
 * optional validation / helper text below.
 *
 * @example
 * // Basic
 * const [val, setVal] = useState<string | null>(null);
 * const opts = [
 *   { value: 'a', label: 'Option A' },
 *   { value: 'b', label: 'Option B', subtext: 'Helper text' },
 *   { value: 'c', label: 'Disabled', disabled: true },
 * ];
 * <BTInputSingleOptions label="Pilih opsi" items={opts} value={val} onChange={setVal} />
 *
 * @example
 * // Required + validator
 * const ref = useRef<BTInputSingleOptionsHandle>(null);
 * <BTInputSingleOptions
 *   label="Status"
 *   items={opts}
 *   value={val}
 *   onChange={setVal}
 *   required
 *   validator={v => v ? null : 'Wajib dipilih'}
 *   ref={ref}
 * />
 * // Trigger validation: ref.current?.validate()
 */
import React from 'react';
import './BTInputSingleOptions.css';
import type {
  BTInputSingleOptionsProps,
  BTInputSingleOptionsHandle,
} from './BTInputSingleOptions.types.js';
import { BTRadioButton } from '../../../atoms/RadioButton/index.js';
import type { BTRadioButtonValue } from '../../../atoms/RadioButton/BTRadioButton.types.js';

export const BTInputSingleOptions = React.forwardRef<
  BTInputSingleOptionsHandle,
  BTInputSingleOptionsProps
>(function BTInputSingleOptions(
  {
    value,
    onChange,
    label,
    required = false,
    items,
    disabled = false,
    errorText,
    helperText,
    name,
    validator,
    className,
  },
  ref,
) {
  const [errorInternal, setErrorInternal] = React.useState<string | null>(null);
  const activeError = errorText ?? errorInternal ?? null;
  const hasError = !!activeError;

  React.useImperativeHandle(
    ref,
    () => ({
      validate() {
        if (!validator) return true;
        const result = validator(value ?? null);
        setErrorInternal(result ?? null);
        return result === null;
      },
    }),
    [validator, value],
  );

  function handleSelect(radioValue: BTRadioButtonValue) {
    if (disabled) return;
    setErrorInternal(null);
    onChange?.(radioValue as Parameters<typeof onChange>[0]);
  }

  const wrapperClass = [
    'bt-input-single-options__wrapper',
    hasError && !disabled && 'bt-input-single-options--error',
    disabled && 'bt-input-single-options--disabled',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <div className={wrapperClass}>
      {/* Label row */}
      {label && (
        <div className="bt-input-single-options__label-row">
          <span className="bt-input-single-options__label">
            {label}
            {required && (
              <span className="bt-input-single-options__required">*</span>
            )}
          </span>
        </div>
      )}

      {/* Radio group */}
      <div
        className="bt-input-single-options__group"
        role="radiogroup"
        aria-required={required || undefined}
        aria-disabled={disabled || undefined}
        aria-invalid={(hasError && !disabled) || undefined}
      >
        {items.map((item) => (
          <BTRadioButton
            key={String(item.value)}
            modelValue={(value ?? '') as BTRadioButtonValue}
            value={item.value as BTRadioButtonValue}
            label={item.label}
            subtext={item.subtext}
            disabled={disabled || !!item.disabled}
            error={hasError && !disabled}
            name={name}
            onChange={handleSelect}
          />
        ))}
      </div>

      {/* Helper / error text — error suppressed when disabled */}
      {((!disabled && activeError) || helperText) && (
        <div className="bt-input-single-options__helper">
          <span
            className={[
              'bt-input-single-options__helper-text',
              hasError && !disabled &&
                'bt-input-single-options__helper-text--error',
            ]
              .filter(Boolean)
              .join(' ')}
          >
            {(!disabled && activeError) || helperText}
          </span>
        </div>
      )}
    </div>
  );
});

BTInputSingleOptions.displayName = 'BTInputSingleOptions';

/**
 * BTInputSingleOptions — labeled radio button group types.
 *
 * Figma node 702-3422.
 */

/** A single option in the radio group. */
export interface BTInputSingleOptionsItem<T = string> {
  /** Unique value emitted when this option is selected. */
  value: T;
  /** Visible label beside the radio circle. */
  label?: string;
  /** Secondary helper text below the label. */
  subtext?: string;
  /** Disables only this option while the group remains active. */
  disabled?: boolean;
}

export interface BTInputSingleOptionsProps<T = string> {
  /** Currently selected value. */
  value?: T | null;
  /** Called when the user selects a new option. */
  onChange?: (value: T | null) => void;
  /** Group label shown above the radio list. */
  label?: string;
  /** Shows a red `*` after the label when true. */
  required?: boolean;
  /** Radio options to render. */
  items: BTInputSingleOptionsItem<T>[];
  /** Disables the entire group. */
  disabled?: boolean;
  /**
   * External error message. When set, all radio circles show the error border
   * and the text is displayed below the group in error colour.
   * Overrides any internal validator error.
   */
  errorText?: string;
  /** Helper text shown below the group in the default state. */
  helperText?: string;
  /** Native `name` attribute shared by all radio inputs for form grouping. */
  name?: string;
  /**
   * Validation function called by `validate()` (via ref handle).
   * Return an error string or null.
   */
  validator?: (value: T | null) => string | null;
  /** Additional CSS class names. */
  className?: string;
}

export interface BTInputSingleOptionsHandle {
  /** Runs the validator and shows the error message. Returns true when valid. */
  validate(): boolean;
}
